+function isUsingBindingStart(source: string, index: number): boolean {
+  const char = source.charCodeAt(index);
+  return char === 0x5b || char === 0x7b || char === 0x24 || char === 0x5f || char === 0x5c || (char >= 0x41 && char <= 0x5a) || (char >= 0x61 && char <= 0x7a) || char > 0x7f;
+}
+
+function isUsingDeclarationStart(parser: Parser): boolean {
+  const index = skipUsingDeclarationTrivia(parser.source, parser.index);
+  return index >= 0 && isUsingBindingStart(parser.source, index);
+}
