          (token & Token.IsPatternStart || (kind & BindingKind.Variable) === 0 || context & Context.Strict))
      ) {
        throw new ParseError(
          tokenStart,
          parser.currentLocation,
          Errors.ForInOfLoopInitializer,
          parser.getToken() === Token.OfKeyword ? 'of' : 'in',
